package com.zorvyn.financebackend.mapper;import com.zorvyn.financebackend.dto.FinancialRecordResponse;import com.zorvyn.financebackend.dto.UserResponse;import com.zorvyn.financebackend.model.AppUser;import com.zorvyn.financebackend.model.FinancialRecord;public final class FinanceMapper {    private FinanceMapper() {    }    public static UserResponse toUserResponse(AppUser user) {        return new UserResponse(user.getId(), user.getName(), user.getEmail(), user.getRole(), user.getStatus());    }    public static FinancialRecordResponse toFinancialRecordResponse(FinancialRecord record) {        return new FinancialRecordResponse(                record.getId(),                record.getAmount(),                record.getType(),                record.getCategory(),                record.getRecordDate(),                record.getNotes(),                record.getCreatedAt(),                record.getUpdatedAt()        );    }}